 1	import React, { FC } from 'react';
 2	import { useLocation } from 'react-router-dom-v5-compat';
 3	
 4	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { Divider, PageSection, PageSectionVariants } from '@patternfly/react-core';
 6	
 7	import Details from './components/Details/Details';
 8	import Services from './components/Services/Services';
 9	import ActiveUserList from './components/UserList/ActiveUserList';
10	
11	import './virtual-machines-instance-details-tab.scss';
12	
13	type VirtualMachinesInstancePageDetailsTabProps = {
14	  obj: V1VirtualMachineInstance;
15	};
16	const VirtualMachinesInstancePageDetailsTab: FC<VirtualMachinesInstancePageDetailsTabProps> = ({
17	  obj: vmi,
18	}) => {
19	  const location = useLocation();
20	
21	  return (
22	    <div className="VirtualMachinesInstanceDetailsTab">
23	      <PageSection variant={PageSectionVariants.light}>
24	        <Details pathname={location?.pathname} vmi={vmi} />
25	      </PageSection>
26	      <Divider />
27	      <PageSection variant={PageSectionVariants.light}>
28	        <Services pathname={location?.pathname} vmi={vmi} />
29	      </PageSection>
30	      <Divider />
31	      <PageSection variant={PageSectionVariants.light}>
32	        <ActiveUserList pathname={location?.pathname} vmi={vmi} />
33	      </PageSection>
34	    </div>
35	  );
36	};
37	
38	export default VirtualMachinesInstancePageDetailsTab;

